You are a fix agent. Resolve the following final-review finding.

Review dimension: UI/UX
Severity: medium
File: src/app/dom-builders.ts:301-310 (makeRowMenu)
Title: Row menu advertises `aria-haspopup='true'` (menu) but does not implement the menu pattern

Finding:
The per-row ⋮ button sets `aria-haspopup='true'` (which per spec is equivalent to `aria-haspopup='menu'`) and toggles `aria-expanded`, signaling to AT users that activating it opens a menu widget with arrow-key item navigation, Home/End, and focus moving to the first item on open. The actual dropdown is a plain `<div class='row-menu'>` containing `<button class='btn'>` / `<a class='btn'>` items with no `role='menu'`/`role='menuitem'`, no focus move into the menu on open, and no arrow-key handling — only Tab/Shift+Tab and Escape work. This expectation mismatch is confusing for screen-reader users. Either complete the menu semantics or downgrade to a plain disclosure. The lower-risk, self-contained fix is to complete the semantics by adding the roles.

Fix instructions (follow exactly; make targeted, minimal changes):
In src/app/dom-builders.ts `createMenu` (which builds the shared `.row-menu` element), set `menu.setAttribute('role', 'menu')` on the created `menu` div, and set `role='menuitem'` on every element in the passed-in `items` array (iterate and set the attribute, skipping any element that already has a role). Then in `makeRowMenu`'s `openMenu`/click handler, after the menu is shown, focus the first item: add `(items[0] as HTMLElement)?.focus()` is not available here, so instead in `createMenu`'s `openMenu`, after positioning, call `(menu.querySelector('button, a') as HTMLElement | null)?.focus()`. Keep `aria-haspopup='true'` and `aria-expanded` toggling as-is. Verify the toolbar-handlers and render-browse tests still pass (they query buttons by text/className, not by role).

## Response Format (required)
Respond with ONLY a single valid JSON object matching the schema below.
- No prose, explanations, or commentary before or after the JSON.
- No markdown code fences (```), no headings — output the raw JSON object.
- Do NOT call any tools and do NOT end your turn on a thinking block. Emit the JSON object directly as text.

JSON schema:
{ approved: Whether the implementation is accepted, feedback: Detailed review feedback, issues: Array<{ file: File with the issue, description: What needs to be fixed, severity: "critical" | "minor" /* How important the fix is */ }> }

/**
 * Tests for the row-menu placement helpers in `dom-builders.ts`:
 *
 *  - `computeMenuPosition` — the pure off-screen flip math (no DOM). By
 *    default a menu opens below + left-aligned with its anchor; when that
 *    would run off a viewport edge it flips direction (down→up, left→right)
 *    and is finally clamped inside the viewport.
 *  - `openMenu` wiring — when a row menu is opened, its real measured size
 *    and the live viewport size are fed into `computeMenuPosition`, so the
 *    flip actually takes effect (not just the pure function in isolation).
 *
 * Environment: happy-dom, which performs NO layout (`getBoundingClientRect`
 * always reports width/height 0). The pure suite is therefore independent of
 * the DOM, and the wiring test injects a synthetic menu rect + viewport via
 * spies/assignment rather than relying on rendered geometry.
 */
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { computeMenuPosition, MENU_EDGE_MARGIN, makeIcon, makeActionButton } from './dom-builders';
import { renderBrowse } from '../app';
import {
  setupCleared,
  browseResult,
  fileEntry,
  rowByName,
  cellsOf,
  installAppTestLifecycle,
} from './test-helpers';

installAppTestLifecycle();

/* A typical ⋮ button rect and a menu size, used across the pure suite. */
const BTN = { left: 900, top: 200, right: 920, bottom: 224 };
const SIZE = { width: 160, height: 140 };
const VIEW = { width: 1000, height: 600 };

describe('computeMenuPosition — default (no overflow)', () => {
  it('opens below + left-aligned with the anchor: left=anchor.left, top=anchor.bottom', () => {
    const anchor = { left: 100, top: 200, right: 120, bottom: 224 };
    const p = computeMenuPosition(anchor, SIZE, VIEW);
    expect(p).toEqual({ left: 100, top: 224 });
  });

  it('keeps the cursor coords for a zero-size (right-click) anchor that fits', () => {
    const cursor = { left: 137, top: 242, right: 137, bottom: 242 };
    const p = computeMenuPosition(cursor, SIZE, VIEW);
    expect(p).toEqual({ left: 137, top: 242 });
  });
});

describe('computeMenuPosition — horizontal flip (would overflow the right edge)', () => {
  it('right-aligns the menu to the anchor right edge instead (open leftward)', () => {
    // anchor.left(900) + width(160) = 1060 > viewport(1000) - margin → flip.
    const p = computeMenuPosition(BTN, SIZE, VIEW);
    expect(p.left).toBe(BTN.right - SIZE.width); // 920 - 160 = 760
    expect(p.top).toBe(BTN.bottom); // vertical still fits → unchanged
  });

  it('right-click near the right edge flips so the menu extends left of the cursor', () => {
    const cursor = { left: 980, top: 100, right: 980, bottom: 100 };
    const p = computeMenuPosition(cursor, SIZE, VIEW);
    expect(p.left).toBe(980 - 160); // 820
  });

  it('does NOT flip when the menu fits within the margin of the right edge', () => {
    // 836 + 160 = 996 == viewport(1000) - margin(4): exactly at the limit, fits.
    const anchor = { left: 836, top: 200, right: 856, bottom: 224 };
    expect(computeMenuPosition(anchor, SIZE, VIEW).left).toBe(836);
  });
});

describe('computeMenuPosition — vertical flip (would overflow the bottom edge)', () => {
  it('opens upward, aligning the menu bottom to the anchor top', () => {
    // anchor.bottom(500) + height(140) = 640 > viewport(600) - margin → flip.
    const anchor = { left: 100, top: 476, right: 120, bottom: 500 };
    const p = computeMenuPosition(anchor, SIZE, VIEW);
    expect(p.top).toBe(anchor.top - SIZE.height); // 476 - 140 = 336
    expect(p.left).toBe(anchor.left); // horizontal still fits → unchanged
  });

  it('right-click near the bottom flips so the menu extends above the cursor', () => {
    const cursor = { left: 100, top: 580, right: 100, bottom: 580 };
    const p = computeMenuPosition(cursor, SIZE, VIEW);
    expect(p.top).toBe(580 - 140); // 440
  });
});

describe('computeMenuPosition — both axes flip at once', () => {
  it('right-aligns AND opens upward when the anchor is in the bottom-right corner', () => {
    const anchor = { left: 900, top: 476, right: 920, bottom: 500 };
    const p = computeMenuPosition(anchor, SIZE, VIEW);
    expect(p).toEqual({ left: 760, top: 336 });
  });
});

describe('computeMenuPosition — clamping into the viewport', () => {
  it('clamps left to the edge margin when a flip would push it off the left edge', () => {
    // Cursor near the left edge + a menu wider than the tiny viewport: the
    // right-align flip computes left = 10 - 160 = -150, which clamps to the
    // margin.
    const tinyView = { width: 100, height: 600 };
    const cursor = { left: 10, top: 200, right: 10, bottom: 224 };
    const p = computeMenuPosition(cursor, SIZE, tinyView);
    expect(p.left).toBe(MENU_EDGE_MARGIN);
  });

  it('clamps top to the edge margin when opening upward would go above the top', () => {
    const tinyView = { width: 1000, height: 100 };
    const anchor = { left: 100, top: 40, right: 120, bottom: 60 };
    const p = computeMenuPosition(anchor, SIZE, tinyView);
    expect(p.top).toBe(MENU_EDGE_MARGIN);
  });
});

/* ===========================================================================
 * makeIcon / makeActionButton — Bootstrap Icons glyphs on menu items.
 *
 * makeIcon builds an empty `<i class="bi bi-<name>">` (the glyph is painted by
 * the bootstrap-icons CSS ::before, so the element has no text content).
 * makeActionButton prepends that glyph when given an `icon` arg, and otherwise
 * behaves exactly as before (label-only, className exactly "btn").
 * ========================================================================= */
describe('makeIcon', () => {
  it('builds an empty <i class="bi bi-<name>"> with no text content', () => {
    const icon = makeIcon('trash');
    expect(icon.tagName).toBe('I');
    expect(icon.className).toBe('bi bi-trash');
    expect(icon.textContent).toBe('');
    expect(icon.children).toHaveLength(0);
  });
});

describe('makeActionButton — icon support', () => {
  it('with an icon: prepends an empty <i class="bi bi-<name>"> as the first child and keeps className exactly "btn"', () => {
    const btn = makeActionButton('Delete', () => undefined, 'trash');
    expect(btn.tagName).toBe('BUTTON');
    expect(btn.className).toBe('btn');
    expect(btn.getAttribute('type')).toBe('button');
    expect(btn.children).toHaveLength(1);
    const icon = btn.firstElementChild as HTMLElement;
    expect(icon.tagName).toBe('I');
    expect(icon.className).toBe('bi bi-trash');
    // The icon adds no text, so the button's textContent is still just the label.
    expect(btn.textContent).toBe('Delete');
  });

  it('without an icon: has no child elements and textContent is the label (default unchanged)', () => {
    const btn = makeActionButton('Search', () => undefined);
    expect(btn.children).toHaveLength(0);
    expect(btn.textContent).toBe('Search');
    expect(btn.className).toBe('btn');
  });
});

/* ===========================================================================
 * makeIcon / makeActionButton — decorative glyphs hidden from assistive tech
 *
 * Bootstrap Icons paint their glyph via a CSS `::before { content: '\f...' }`
 * rule, and some screen readers announce generated content / private-use-area
 * code points as stray noise. Every glyph produced by `makeIcon` is paired
 * with a visible text label (the menu item's label), so the glyph is purely
 * decorative and MUST be hidden from the accessibility tree via
 * `aria-hidden="true"` (WCAG 1.3.1). `makeIcon` is the central builder for
 * every menu-item glyph, so hiding it there covers all menu icons at once.
 * ========================================================================= */
describe('makeIcon — decorative glyph hidden from assistive tech (WCAG 1.3.1)', () => {
  // The full set of icon names passed to makeIcon across the browse view's
  // row menus (Download/Upload/Delete/Move/Copy) and the dir menu
  // (Upload/New directory). Each must be hidden from AT.
  it.each(['upload', 'download', 'trash', 'arrows-move', 'files', 'folder-plus'])(
    'sets aria-hidden="true" on the bi-%s glyph',
    (name) => {
      expect(makeIcon(name).getAttribute('aria-hidden')).toBe('true');
    },
  );

  it('hides the glyph for an arbitrary icon name not special-cased above', () => {
    expect(makeIcon('house').getAttribute('aria-hidden')).toBe('true');
  });
});

describe('makeActionButton — icon hidden from assistive tech (WCAG 1.3.1)', () => {
  it('the prepended icon glyph carries aria-hidden="true"', () => {
    const btn = makeActionButton('Delete', () => undefined, 'trash');
    const icon = btn.firstElementChild as HTMLElement;
    expect(icon.getAttribute('aria-hidden')).toBe('true');
  });
});

/* ===========================================================================
 * openMenu wiring — the measured menu size + live viewport drive the flip.
 *
 * happy-dom reports a 0×0 rect for every element, so we spy on the menu's
 * getBoundingClientRect to inject a known size and shrink window.innerWidth/
 * innerHeight to force an overflow, then assert the menu's inline left/top
 * match what computeMenuPosition would produce.
 * ========================================================================= */
describe('openMenu applies computeMenuPosition to the rendered menu', () => {
  const file = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false, size: 10 });

  let savedW: number;
  let savedH: number;

  beforeEach(() => {
    savedW = window.innerWidth;
    savedH = window.innerHeight;
    // Ensure no menu is left open by a prior test.
    document.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));
  });
  afterEach(() => {
    window.innerWidth = savedW;
    window.innerHeight = savedH;
  });

  function menuOf(results: HTMLElement): HTMLElement {
    const row = rowByName(results.querySelector('table')!, 'a.txt')!;
    return cellsOf(row)[3].querySelector('.row-menu') as HTMLElement;
  }

  it('flips up + right when the right-click point is in the bottom-right corner', async () => {
    window.innerWidth = 1000;
    window.innerHeight = 600;
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [file] }));
    const menu = menuOf(results);
    vi.spyOn(menu, 'getBoundingClientRect').mockReturnValue({
      left: 0,
      top: 0,
      right: 160,
      bottom: 140,
      width: 160,
      height: 140,
      x: 0,
      y: 0,
      toJSON() {},
    });

    const row = rowByName(results.querySelector('table')!, 'a.txt')!;
    row.dispatchEvent(
      new MouseEvent('contextmenu', {
        cancelable: true,
        bubbles: true,
        clientX: 900,
        clientY: 500,
      }),
    );

    // Cursor anchor {900,500,900,500}, size 160×140, viewport 1000×600:
    // horizontal flip → left = 900 - 160 = 740; vertical flip → top = 500 - 140 = 360.
    expect(menu.hidden).toBe(false);
    expect(menu.style.left).toBe('740px');
    expect(menu.style.top).toBe('360px');
  });

  it('leaves the cursor position untouched when the menu fits (no measured overflow)', async () => {
    // Default happy-dom viewport (1024×768) with a measured size that fits.
    window.innerWidth = 1024;
    window.innerHeight = 768;
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [file] }));
    const menu = menuOf(results);
    vi.spyOn(menu, 'getBoundingClientRect').mockReturnValue({
      left: 0,
      top: 0,
      right: 160,
      bottom: 60,
      width: 160,
      height: 60,
      x: 0,
      y: 0,
      toJSON() {},
    });

    const row = rowByName(results.querySelector('table')!, 'a.txt')!;
    row.dispatchEvent(
      new MouseEvent('contextmenu', {
        cancelable: true,
        bubbles: true,
        clientX: 137,
        clientY: 242,
      }),
    );

    expect(menu.hidden).toBe(false);
    expect(menu.style.left).toBe('137px');
    expect(menu.style.top).toBe('242px');
  });
});

/**
 * Tests for the toolbar handlers — the search button / Enter-key handler, the
 * clear-search handler, and the upload (change) handler, including the
 * per-file upload error-handling contract.
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). Shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 */
import { describe, it, expect, vi } from 'vitest';
import { toBrowseHash, toSearchHash } from '../router';
import { normalizeRelativePath } from '../format';
import { mockResponse } from '../test-utils/mock-response';
import {
  setup,
  flush,
  browseResult,
  fileEntry,
  joinPathHelper,
  fetchMock,
  installAppTestLifecycle,
} from './test-helpers';
import { clearSearch, pickAndUploadInto } from './toolbar-handlers';

installAppTestLifecycle();

/* ===========================================================================
 * Toolbar handlers
 * ========================================================================= */
describe('toolbar handlers', () => {
  describe('search', () => {
    it('navigates to a search hash 200ms after the user types in the input (debounced)', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000); // settle initial render

        searchInput.value = 'hello world';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));

        // Not yet — debounce hasn't fired
        expect(window.location.hash).toBe(toBrowseHash('docs'));

        vi.advanceTimersByTime(200);
        expect(window.location.hash).toBe(toSearchHash('hello world', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('resets the debounce timer on each keystroke (only fires after 200ms of silence)', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = 'h';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(150); // not enough
        searchInput.value = 'he';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(150); // 150ms since last keystroke, still not enough
        expect(window.location.hash).toBe(toBrowseHash('docs'));

        vi.advanceTimersByTime(50); // now 200ms since last keystroke
        expect(window.location.hash).toBe(toSearchHash('he', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('trims the query before navigating', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = '   spaced   ';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(200);

        expect(window.location.hash).toBe(toSearchHash('spaced', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('clears the search (returns to browse) when the query becomes empty', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = '';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(200);

        expect(window.location.hash).toBe(toBrowseHash('docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('clears the search input and navigates to browse when the X (clear) button is clicked', async () => {
      const { searchInput, searchClearBtn } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'foo';
      searchClearBtn.click();

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('clears the search input and navigates to browse when Escape is pressed', async () => {
      const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'foo';
      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('Escape key stops propagation (does not close the parent <dialog>)', async () => {
      const { searchInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      const parentEl = searchInput.closest('.file-browser') ?? document.body;
      parentEl.addEventListener('keydown', () => {
        // should NOT fire if stopPropagation worked
      });

      const event = new KeyboardEvent('keydown', { key: 'Escape', bubbles: true });
      const stopSpy = vi.spyOn(event, 'stopPropagation');
      searchInput.dispatchEvent(event);

      expect(stopSpy).toHaveBeenCalled();
    });

    it('still navigates immediately when Enter is pressed (bypasses debounce)', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = 'foo';
        searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter' }));

        // Enter fires immediately, no debounce wait needed
        expect(window.location.hash).toBe(toSearchHash('foo', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });
  });

  describe('clearSearch', () => {
    // clearSearch() is the explicit "clear the search box and return to browse"
    // handler (e.g. an "×" / Clear button). It must (1) blank the shared search
    // input, (2) read the CURRENT route's path, and (3) navigate to the browse
    // hash for that path — mirroring doSearch()'s empty-query branch, but as a
    // dedicated, unconditional entry point that also wipes the input text.

    it('resets the search input value to an empty string', async () => {
      const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'leftover query';
      clearSearch();
      await flush();

      expect(searchInput.value).toBe('');
    });

    it('navigates to the browse hash for the current browse path', async () => {
      setup({ hash: toBrowseHash('docs/sub') });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash(normalizeRelativePath('docs/sub')));
    });

    it('uses the current route path even when the app is showing a search view', async () => {
      // A search route carries its own `path` (the search scope); clearSearch
      // must drop the query and return to browsing THAT path, not root.
      setup({ hash: toSearchHash('anything', 'docs') });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('normalizes the current path before building the browse hash', async () => {
      // A trailing slash (or backslashes) in the current path is collapsed by
      // normalizeRelativePath so the resulting browse hash is canonical.
      setup({ hash: toBrowseHash('docs/') });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('navigates to the root browse hash when the current path is empty', async () => {
      setup({ hash: '' });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash(''));
    });

    it('clears the input and navigates to browse together', async () => {
      const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'stale text';
      clearSearch();
      await flush();

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });
  });

  describe('upload', () => {
    function setFiles(input: HTMLInputElement, names: string[]): void {
      const dt = new DataTransfer();
      for (const n of names) dt.items.add(new File(['data-' + n], n));
      input.files = dt.files as unknown as FileList;
    }

    /** Drain queued microtasks enough times for the upload loop + re-render. */
    const settle = async (n = 10): Promise<void> => {
      for (let i = 0; i < n; i++) await flush();
    };

    /**
     * Build a fetch impl that rejects POST /upload for the named files (via a
     * non-ok Response, exactly how `ApiClient.request` surfaces failures) while
     * still serving normal browse/upload responses for everything else.
     */
    function failingUploadImpl(failingNames: string[]) {
      const failing = new Set(failingNames);
      return async (url: string, init?: RequestInit): Promise<Response> => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'POST' && u.includes('/upload')) {
          const file = (init?.body as FormData | undefined)?.get('file') as File | null;
          if (file && failing.has(file.name)) {
            return mockResponse({ ok: false, status: 413, text: 'too large' });
          }
          return mockResponse({ status: 200, body: { path: file?.name ?? '' } });
        }
        if (method === 'GET' && u.includes('/browse')) {
          const raw = u.split('path=')[1] ?? '';
          const path = decodeURIComponent(raw);
          const child = 'child-of-' + (path || 'root');
          return mockResponse({
            body: browseResult({
              path,
              entries: [fileEntry({ name: child, path: joinPathHelper(path, child) })],
              fileCount: 1,
              totalSize: 10,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      };
    }

    /** Ordered names of files POSTed to /upload so far. */
    function uploadedFileNames(): string[] {
      return fetchMock.mock.calls
        .filter(([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST')
        .map(
          ([, init]) =>
            ((init?.body as FormData | undefined)?.get('file') as File | null)?.name ?? '',
        );
    }

    /** Count of GET /browse calls observed so far. */
    function browseCount(): number {
      return fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/browse') && (init?.method ?? 'GET') === 'GET',
      ).length;
    }

    it('uploads each selected file to the current browse path, then clears the input and re-renders', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await flush();
      await flush();

      const uploadCalls = fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST',
      );
      expect(uploadCalls).toHaveLength(2);
      for (const [, init] of uploadCalls) {
        expect(init?.body).toBeInstanceOf(FormData);
        expect((init!.body as FormData).get('file')).toBeInstanceOf(File);
      }
      // All uploads target the current browse path.
      expect(
        uploadCalls.every(([u]) => String(u).includes('path=' + encodeURIComponent('docs'))),
      ).toBe(true);
      // The input is cleared afterwards.
      expect(uploadInput.value).toBe('');
      // And a re-render occurred (browse fetched again after upload).
      const browseCalls = fetchMock.mock.calls.filter(([u]) => String(u).includes('/browse'));
      expect(browseCalls.length).toBeGreaterThan(0);
    });

    it('uploads nothing when no files are selected', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      uploadInput.dispatchEvent(new Event('change'));
      await flush();

      expect(fetchMock.mock.calls.some(([u]) => String(u).includes('/upload'))).toBe(false);
    });

    // ---- per-file error handling -------------------------------------------
    // A single failing upload must NOT abort the remaining uploads, swallow the
    // re-render, or leave the input uncleared. Each failure is surfaced in the
    // status footer (see task spec: "Uploaded N file(s); failed: a.txt, b.txt").

    it('continues uploading the remaining files when a middle upload fails, then clears the input, re-renders, and surfaces the failure', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['b.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['a.txt', 'b.txt', 'c.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      // All three uploads were attempted — including the failing one — in order.
      expect(uploadedFileNames()).toEqual(['a.txt', 'b.txt', 'c.txt']);
      // The input is cleared even though one upload failed.
      expect(uploadInput.value).toBe('');
      // A re-render still happened after the upload loop.
      expect(browseCount()).toBeGreaterThan(browseBefore);
      // The failure is surfaced in the status footer: it names the failing
      // file and acknowledges the two files that did upload.
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('b.txt');
      expect(status.textContent).toMatch(/Uploaded\s+2/i);
      // Successful files are not flagged as failed.
      expect(status.textContent).not.toContain('c.txt');
      expect(status.textContent).not.toContain('a.txt');
    });

    it('continues uploading subsequent files when the first upload fails', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['bad.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['bad.txt', 'good.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['bad.txt', 'good.txt']);
      expect(uploadInput.value).toBe('');
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('bad.txt');
      expect(status.textContent).not.toContain('good.txt');
    });

    it('clears the input, re-renders, and lists every failure when all uploads fail', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['x.txt', 'y.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['x.txt', 'y.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['x.txt', 'y.txt']);
      expect(uploadInput.value).toBe('');
      expect(browseCount()).toBeGreaterThan(browseBefore);
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('x.txt');
      expect(status.textContent).toContain('y.txt');
    });

    it('does not surface a failure message when every upload succeeds (status stays the normal browse summary)', async () => {
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadInput.value).toBe('');
      // No failure report; renderBrowse's normal "N folders, M files, total S"
      // summary is what the re-render leaves behind.
      expect(status.textContent).not.toMatch(/failed/i);
      expect(status.textContent).toMatch(/folders.*files.*total/);
    });
  });

  describe('pickAndUploadInto (upload into an arbitrary folder)', () => {
    // Exercises pickAndUploadInto directly: it builds a transient
    // <input type=file multiple>, awaits its change/cancel, uploads every
    // chosen file into the GIVEN path (not the current route), then removes
    // the input and re-renders — mirroring handleUpload's contract but with a
    // caller-chosen destination.

    /** Grab the transient picker input that pickAndUploadInto appended to body. */
    function findPickerInput(): HTMLInputElement | undefined {
      // The transient input is a DIRECT child of <body>; the toolbar upload
      // input lives inside <label class="btn">, so its parent is not body.
      return Array.from(document.querySelectorAll('input[type=file]')).find(
        (i) => i.parentElement === document.body,
      ) as HTMLInputElement | undefined;
    }

    function setFiles(input: HTMLInputElement, names: string[]): void {
      const dt = new DataTransfer();
      for (const n of names) dt.items.add(new File(['data-' + n], n));
      input.files = dt.files as unknown as FileList;
    }

    const settle = async (n = 10): Promise<void> => {
      for (let i = 0; i < n; i++) await flush();
    };

    function uploadCalls(): [string, RequestInit | undefined][] {
      return fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST',
      );
    }

    it('creates a hidden <input type=file multiple> appended to body, then uploads each file into the given path', async () => {
      setup({ hash: toBrowseHash('current/dir') });
      await flush();

      // Suspend on the awaited picker: do NOT await yet.
      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      expect(pickInput, 'a transient picker input must be appended to body').toBeTruthy();
      expect(pickInput!.type).toBe('file');
      expect(pickInput!.multiple).toBe(true);

      setFiles(pickInput!, ['a.txt', 'b.txt']);
      pickInput!.dispatchEvent(new Event('change'));
      await p;
      await settle();

      // Uploads target the GIVEN path, NOT the current route.
      expect(uploadCalls()).toHaveLength(2);
      expect(
        uploadCalls().every(([u]) =>
          String(u).includes('path=' + encodeURIComponent('target/folder')),
        ),
      ).toBe(true);
      // The transient input was removed after the upload loop.
      expect(findPickerInput()).toBeUndefined();
    });

    it('uploads nothing and removes the input when the picker is cancelled (no files)', async () => {
      setup({ hash: toBrowseHash('docs') });
      await flush();

      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      expect(pickInput).toBeTruthy();

      // Dismiss the picker without choosing — the `cancel` event resolves
      // the awaited promise with an empty list.
      pickInput!.dispatchEvent(new Event('cancel'));
      await p;
      await settle();

      expect(uploadCalls()).toHaveLength(0);
      expect(findPickerInput()).toBeUndefined();
    });

    it('surfaces per-file failures in the status footer while still uploading the rest', async () => {
      fetchMock.mockImplementation(async (url: string, init?: RequestInit) => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'POST' && u.includes('/upload')) {
          const file = (init?.body as FormData | undefined)?.get('file') as File | null;
          if (file && file.name === 'bad.txt') {
            return mockResponse({ ok: false, status: 413, text: 'too large' });
          }
          return mockResponse({ status: 200, body: { path: file?.name ?? '' } });
        }
        if (method === 'GET' && u.includes('/browse')) {
          return mockResponse({ body: browseResult({ path: 'target/folder', entries: [] }) });
        }
        return mockResponse({ status: 200, body: {} });
      });
      const { status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      setFiles(pickInput!, ['good.txt', 'bad.txt']);
      pickInput!.dispatchEvent(new Event('change'));
      await p;
      await settle();

      // Both were attempted; only bad.txt is flagged.
      expect(
        uploadCalls().map(([, init]) => ((init!.body as FormData).get('file') as File).name),
      ).toEqual(['good.txt', 'bad.txt']);
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('bad.txt');
      expect(status.textContent).not.toContain('good.txt');
    });
  });
});

/**
 * Tests for `renderBrowse` — the browse-result renderer (table headers, rows,
 * columns, in-app navigation, the Actions column with Download/Delete/Move/Copy
 * + their error surfacing, the breadcrumb, and the status footer).
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). Shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 *
 * Contract decisions encoded here (carried over from the monolith):
 *  - In-app navigation (directory name links, the ".." parent row, breadcrumb
 *    segments) is verified by asserting on `window.location.hash` after a
 *    click — robust to either a `navigate(...)` call OR an
 *    `<a href="#...">` (happy-dom follows hash-fragment href clicks).
 *  - The results table uses a `<thead>` (header `<th>` row) and a `<tbody>`
 *    (data `<td>` rows). Column order for browse is
 *    `Name | Size | Modified | Actions`.
 *  - `renderBrowse` operates against the DOM context `startApp` establishes
 *    (module-level element refs), so every test calls `setup()`/`setupCleared()`
 *    first.
 */
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { renderBrowse } from '../app';
import { toBrowseHash } from '../router';
import { formatBytes, normalizeRelativePath } from '../format';
import { mockResponse } from '../test-utils/mock-response';
import {
  setup,
  setupCleared,
  flush,
  browseResult,
  fileEntry,
  dataRows,
  rowByName,
  cellsOf,
  clickNameLink,
  buttonsByText,
  fetchMock,
  ISO_FMT,
  installAppTestLifecycle,
} from './test-helpers';

installAppTestLifecycle();

/* ===========================================================================
 * renderBrowse — table, rows, columns, navigation, actions
 * ========================================================================= */
describe('renderBrowse', () => {
  it('builds a table with header Name | Size | Modified | (blank Actions header)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [] }));

    const table = results.querySelector('table');
    expect(table).toBeTruthy();
    const headers = Array.from(table!.querySelectorAll('th')).map((h) => h.textContent!.trim());
    // The Actions column has no visible header label now: the 4th <th> is
    // empty, but all four <th> remain so the header column count lines up
    // with the four <td> per body row (uniform :nth-child targeting).
    expect(headers).toEqual(['Name', 'Size', 'Modified', '']);
  });

  it('tags the browse table with the browse-table class alongside results-table', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [] }));

    const table = results.querySelector('table')!;
    expect(table.classList.contains('results-table')).toBe(true);
    expect(table.classList.contains('browse-table')).toBe(true);
  });

  it('keeps the Actions column header th empty but present (four header cells)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [] }));

    const headers = Array.from(results.querySelector('table')!.querySelectorAll('thead th'));
    expect(headers).toHaveLength(4);
    expect(headers[3].textContent).toBe('');
  });

  it('keeps four td per body row so column counts line up with the header', async () => {
    const entries = [
      fileEntry({ name: 'a.txt', isDirectory: false, size: 10 }),
      fileEntry({ name: 'sub', isDirectory: true }),
    ];
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries }));

    for (const row of dataRows(results.querySelector('table')!)) {
      expect(cellsOf(row)).toHaveLength(4);
    }
  });

  it('renders one data row per entry when there is no parent', async () => {
    const entries = [
      fileEntry({ name: 'a.txt', isDirectory: false, size: 10 }),
      fileEntry({ name: 'sub', isDirectory: true }),
    ];
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries }));

    expect(dataRows(results.querySelector('table')!)).toHaveLength(2);
  });

  it('prepends a ".." parent row only when result.parent is not null', async () => {
    const entry = fileEntry({ name: 'a.txt' });
    const { results } = await setupCleared();

    renderBrowse(browseResult({ path: 'docs/sub', parent: 'docs', entries: [entry] }));
    const tableWithParent = results.querySelector('table')!;
    const rowsWithParent = dataRows(tableWithParent);
    expect(rowsWithParent).toHaveLength(2);
    expect(cellsOf(rowsWithParent[0])[0].textContent?.trim()).toBe('..');

    results.innerHTML = '';
    renderBrowse(browseResult({ path: 'docs', parent: null, entries: [entry] }));
    const tableNoParent = results.querySelector('table')!;
    expect(dataRows(tableNoParent)).toHaveLength(1);
    expect(cellsOf(dataRows(tableNoParent)[0])[0].textContent?.trim()).toBe('a.txt');
  });

  it('clicking the ".." row navigates to toBrowseHash(result.parent)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs/sub', parent: 'docs', entries: [] }));
    const parentRow = rowByName(results.querySelector('table')!, '..')!;

    clickNameLink(parentRow);

    expect(window.location.hash).toBe(toBrowseHash('docs'));
  });

  describe('directory rows', () => {
    it('renders the name and an em-dash size, and clicking the name navigates into the folder', async () => {
      const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

      const row = rowByName(results.querySelector('table')!, 'sub')!;
      const [nameCell, sizeCell] = cellsOf(row);
      expect(nameCell.textContent?.trim()).toBe('sub');
      expect(sizeCell.textContent?.trim()).toBe('—');

      clickNameLink(row);
      expect(window.location.hash).toBe(toBrowseHash('docs/sub'));
    });
  });

  describe('file rows', () => {
    const file = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false, size: 1536 });

    it('renders the name as plain text (no navigation link)', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      const row = rowByName(results.querySelector('table')!, 'a.txt')!;
      const [nameCell] = cellsOf(row);
      expect(nameCell.textContent?.trim()).toBe('a.txt');
      expect(nameCell.querySelector('a, button')).toBeNull();
    });

    it('shows formatBytes(size) for the Size column', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      const row = rowByName(results.querySelector('table')!, 'a.txt')!;
      const sizeCell = cellsOf(row)[1];
      expect(sizeCell.textContent?.trim()).toBe(formatBytes(1536));
      expect(sizeCell.textContent?.trim()).toBe('1.5 KB');
    });

    it('shows formatDate(lastModified) for the Modified column', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      const row = rowByName(results.querySelector('table')!, 'a.txt')!;
      const modifiedCell = cellsOf(row)[2];
      expect(modifiedCell.textContent?.trim()).toBe(ISO_FMT);
    });

    it('escapes names via textContent (no HTML injection)', async () => {
      const evil = fileEntry({
        name: '<img src=x onerror=alert(1)>',
        path: 'docs/x',
        isDirectory: false,
      });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [evil] }));

